import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Divider,
  Badge,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Category to Color Token Mapping
 * Based on the design specification.
 */
const getCategoryColors = (category: string = '') => {
  const cat = category.toLowerCase().replace(/[^a-z]/g, '');

  if (cat === 'noblegas') {
    return { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-800)', label: 'Noble Gas' };
  }
  if (cat === 'alkalimetal') {
    return { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-800)', label: 'Alkali Metal' };
  }
  if (cat === 'alkalineearthmetal' || cat === 'alkalineearth') {
    return { bg: 'var(--ggui-color-warning-100)', text: 'var(--ggui-color-warning-800)', label: 'Alkaline Earth' };
  }
  if (cat === 'nonmetal') {
    return { bg: 'var(--ggui-color-info-100)', text: 'var(--ggui-color-info-800)', label: 'Non-metal' };
  }
  if (cat === 'transitionmetal') {
    return { bg: 'var(--ggui-color-neutral-100)', text: 'var(--ggui-color-neutral-800)', label: 'Transition Metal' };
  }
  if (cat === 'metalloid') {
    return { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-800)', label: 'Metalloid' };
  }
  if (cat === 'halogen') {
    return { bg: 'var(--ggui-color-success-200)', text: 'var(--ggui-color-success-900)', label: 'Halogen' };
  }

  // Default fallback
  return { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)', label: category };
};

const LEGEND_CATEGORIES = [
  'Alkali Metal',
  'Alkaline Earth',
  'Transition Metal',
  'Metalloid',
  'Non-metal',
  'Halogen',
  'Noble Gas',
];

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.map((el) => ({
      ...el,
      isMatch: el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query),
    }));
  }, [elements, searchQuery]);

  const hasMatches = useMemo(() => {
    if (!searchQuery.trim()) return true;
    return filteredElements.some((el: any) => el.isMatch);
  }, [filteredElements, searchQuery]);

  const handleElementClick = (el: ElementData) => {
    setSelectedElement(el);
  };

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ minWidth: '300px' }}>
            <SearchField
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Main Grid Area */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}>
          <Box
            role="grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(45px, 1fr))',
              gridAutoRows: 'minmax(60px, auto)',
              gap: 'var(--ggui-spacing-1)',
              minWidth: '900px', // Ensures legibility on smaller viewports with overflow
            }}
          >
            {filteredElements.map((el: any) => {
              const colors = getCategoryColors(el.category);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const isMatch = el.isMatch !== false;

              return (
                <Box
                  key={el.atomicNumber}
                  as="button"
                  role="gridcell"
                  aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`}
                  onClick={() => handleElementClick(el)}
                  style={{
                    gridColumn: el.col,
                    gridRow: el.row,
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'space-between',
                    alignItems: 'flex-start',
                    padding: 'var(--ggui-spacing-1) var(--ggui-spacing-2)',
                    backgroundColor: colors.bg,
                    color: colors.text,
                    border: '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    cursor: 'pointer',
                    transition: 'all 200ms ease-out',
                    opacity: isMatch ? 1 : 0.2,
                    filter: isMatch ? 'none' : 'grayscale(1)',
                    outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                    outlineOffset: '1px',
                    position: 'relative',
                    zIndex: isSelected ? 10 : 1,
                    // Hover effect
                    transform: 'scale(1)',
                  }}
                  // Using CSS-in-JS pattern for hover scale since inline style transition is needed
                  onMouseEnter={(e) => {
                    e.currentTarget.style.transform = 'scale(1.05)';
                    e.currentTarget.style.zIndex = '20';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.transform = 'scale(1)';
                    e.currentTarget.style.zIndex = isSelected ? '10' : '1';
                  }}
                >
                  <Text variant="caption" color="inherit" weight="semibold">
                    {el.atomicNumber}
                  </Text>
                  <Box style={{ width: '100%', textAlign: 'center' }}>
                    <Text size="lg" weight="bold" color="inherit">
                      {el.symbol}
                    </Text>
                  </Box>
                  <Box style={{ height: '4px' }} />
                </Box>
              );
            })}
          </Box>
          {!hasMatches && (
            <Box paddingY={40}>
              <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
                No elements match your search.
              </Text>
            </Box>
          )}
        </Box>

        {/* Legend Section */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap align="center">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Legend:
          </Text>
          {LEGEND_CATEGORIES.map((cat) => {
            const colors = getCategoryColors(cat);
            return (
              <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1)">
                <Box
                  style={{
                    width: '16px',
                    height: '16px',
                    backgroundColor: colors.bg,
                    border: '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                  }}
                />
                <Text variant="caption" weight="medium">
                  {cat}
                </Text>
              </Stack>
            );
          })}
        </Stack>

        {/* Detail Panel */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
            <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>
                  {selectedElement.name} <Text as="span" weight="normal" color="var(--ggui-color-onSurfaceVariant)">({selectedElement.symbol})</Text>
                </Heading>

                <Divider margin={4} />

                <Stack direction="horizontal" gap="var(--ggui-spacing-12)" wrap>
                  {/* Left Column */}
                  <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '200px' }}>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                      <Text weight="bold">{selectedElement.atomicNumber}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                      <Box>
                        <Badge 
                          variant="primary" 
                          style={{ 
                            backgroundColor: getCategoryColors(selectedElement.category).bg,
                            color: getCategoryColors(selectedElement.category).text,
                            border: '1px solid var(--ggui-color-outlineVariant)'
                          }}
                        >
                          {getCategoryColors(selectedElement.category).label}
                        </Badge>
                      </Box>
                    </Stack>
                  </Stack>

                  {/* Right Column */}
                  <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '200px' }}>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                      <Text weight="bold">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                      <Text weight="bold">Row {selectedElement.row}, Column {selectedElement.col}</Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}
